        border: 3px solid #00d4ff;
        overflow: hidden;
        box-shadow: 0 0 40px rgba(0,212,255,0.6);
    ">
        <!-- Digital Grid Lines -->
        <div style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: repeating-linear-gradient(0deg, transparent, transparent 20px, rgba(0,212,255,0.1) 20px, rgba(0,212,255,0.1) 21px); pointer-events: none;"></div>
        <div style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: repeating-linear-gradient(90deg, transparent, transparent 20px, rgba(0,212,255,0.1) 20px, rgba(0,212,255,0.1) 21px); pointer-events: none;"></div>

        <!-- Iris Blades (8 segments) -->
        <div style="
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
