        ">
            <!-- Center Circle (shrinks) -->
            <div style="
                position: absolute;
                top: 50%;
                left: 50%;
                transform: translate(-50%, -50%);
                width: 250px;
                height: 250px;
                border-radius: 50%;
                background: linear-gradient(135deg, #1a1f3a 0%, #0a0e27 100%);
                border: 3px solid #00d4ff;
                box-shadow: 0 0 40px rgba(0,212,255,0.8), inset 0 0 30px rgba(0,212,255,0.3);
                animation: iris-close 2s ease-out forwards;
            ">
                <!-- Scanning Lines -->
                <div style="position: absolute; top: 30%; left: 0; width: 100%; height: 2px; background: #00d4ff; animation: scan-line 1.5s ease-out;"></div>
                <div style="position: absolute; top: 50%; left: 0; width: 100%; height: 2px; background: #00d4ff; animation: scan-line 1.7s ease-out;"></div>
                <div style="position: absolute; top: 70%; left: 0; width: 100%; height: 2px; background: #00d4ff; animation: scan-line 1.9s ease-out;"></div>
            </div>
        </div>

        <!-- Blue Energy Burst -->
        <div style="
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            width: 400px;
            height: 400px;
            background: radial-gradient(circle, rgba(0,212,255,0.6) 0%, transparent 70%);
            animation: energy-pulse 2s ease-out;
            opacity: 0;
        "></div>

        <!-- Digital Particles -->
        <div style="position: absolute; top: 30%; left: 30%; font-size: 12px; color: #00d4ff; animation: digital-disperse-1 2s ease-out; opacity: 0;">▪</div>
        <div style="position: absolute; top: 40%; right: 25%; font-size: 14px; color: #00ff88; animation: digital-disperse-2 2.2s ease-out; opacity: 0;">▫</div>
        <div style="position: absolute; top: 60%; left: 20%; font-size: 10px; color: #00d4ff; animation: digital-disperse-3 2.4s ease-out; opacity: 0;">▪</div>
