                NEXT MODULE READY
            </div>
        </div>
    </div>

    <!-- Access Code Obtained -->
    <div style="
        text-align: center;
        margin-top: 20px;
        animation: bounce-in 1s ease-out 1.8s backwards;
    ">
        <div style="
            display: inline-block;
            background: linear-gradient(135deg, #00d4ff 0%, #00ff88 100%);
            padding: 15px 30px;
            border-radius: 50px;
            box-shadow: 0 5px 20px rgba(0,212,255,0.6);
            font-family: 'Courier New', monospace;
        ">
            <span style="font-size: 30px;">🔐</span>
            <span style="font-size: 18px; font-weight: bold; color: #000; margin-left: 10px;">
                ACCESS CODE OBTAINED
            </span>
        </div>
    </div>
</div>

<style>
@keyframes iris-close {
    0% { transform: translate(-50%, -50%) scale(1); opacity: 1; }
