    0% { opacity: 1; transform: translate(0, 0); }
    100% { opacity: 0; transform: translate(60px, -40px); }
}

@keyframes digital-disperse-3 {
    0% { opacity: 1; transform: translate(0, 0); }
    100% { opacity: 0; transform: translate(-40px, 50px); }
}

@keyframes digital-disperse-4 {
    0% { opacity: 1; transform: translate(0, 0); }
    100% { opacity: 0; transform: translate(50px, 60px); }
}
</style>
```

